// LENIS
(function(){
  if(typeof Lenis==='undefined')return;
  const lenis=new Lenis({lerp:.09,smoothWheel:true,smoothTouch:false});
  lenis.on('scroll',()=>{
    // Fire all registered scroll callbacks
    if(window.__lenisScrollCbs) window.__lenisScrollCbs.forEach(fn=>fn());
  });
  function raf(t){lenis.raf(t);requestAnimationFrame(raf);}
  requestAnimationFrame(raf);
  window.__lenis=lenis;
  document.querySelectorAll('a[href^="#"]').forEach(a=>{
    a.addEventListener('click',e=>{
      const id=a.getAttribute('href');
      if(id==='#')return;
      const t=document.querySelector(id);
      if(t){e.preventDefault();lenis.scrollTo(t,{duration:1.2});}
    });
  });
})();

// HEADER scroll
window.addEventListener('scroll',()=>{
  document.getElementById('site-header').classList.toggle('scrolled',window.scrollY>40);
  // Hero fade-out on scroll
  const hero = document.getElementById('hero');
  if(hero){
    const fade = Math.max(0, 1 - (window.scrollY / (window.innerHeight * 0.7)));
    hero.style.opacity = fade;
  }
},{passive:true});

// BURGER
(function(){
  const btn=document.getElementById('burger');
  const menu=document.getElementById('mobile-menu');
  const links=menu.querySelectorAll('a');
  let open=false;
  function toggle(v){
    open=v!==undefined?v:!open;
    btn.classList.toggle('open',open);
    btn.setAttribute('aria-expanded',open);
    menu.classList.toggle('open',open);
    document.body.style.overflow=open?'hidden':'';
    if(open) links.forEach((l,i)=>{l.classList.remove('in');setTimeout(()=>l.classList.add('in'),i*65+40);});
    else links.forEach(l=>l.classList.remove('in'));
  }
  btn.addEventListener('click',()=>toggle());
  links.forEach(l=>l.addEventListener('click',()=>toggle(false)));
  document.addEventListener('keydown',e=>{if(e.key==='Escape'&&open)toggle(false);});
})();

// REVEAL + SCROLL ANIMATIONS — deferred until after loader so nothing fires while hidden
// Both observers are initialised at 3 600 ms, just after the loader begins its fade-out,
// so every element plays its entrance animation as the page is revealed.
setTimeout(function(){

  // REVEAL — one-way (fires once, stays in)
  (function(){
    var obs = new IntersectionObserver(function(entries){
      entries.forEach(function(e){
        if(e.isIntersecting){ e.target.classList.add('in'); obs.unobserve(e.target); }
      });
    },{threshold:.08, rootMargin:'0px 0px -40px 0px'});
    document.querySelectorAll('.reveal').forEach(function(el){ obs.observe(el); });
  })();

  // SCROLL ANIMATION — bidirectional: resets when scrolled back up, replays on re-entry
  (function(){
    var els = document.querySelectorAll('.anim-el');
    if(!els.length) return;
    var observer = new IntersectionObserver(function(entries){
      entries.forEach(function(e){
        if(e.intersectionRatio >= 0.1){
          e.target.classList.add('anim-in');
        } else if(e.intersectionRatio === 0){
          e.target.classList.remove('anim-in');
        }
      });
    },{threshold:[0, 0.1], rootMargin:'0px 0px -50px 0px'});
    els.forEach(function(el){ observer.observe(el); });
  })();

}, 3600);

// HERO — Interactive solar canvas
(function(){
  const cv=document.getElementById('solar-canvas');
  if(!cv)return;
  const ctx=cv.getContext('2d');
  const DPR=Math.min(window.devicePixelRatio||1,2);
  let W,H,cols,rows,cells=[];
  let mx=-9999,my=-9999,smx=0,smy=0;
  const CW=52,CH=38,GAP=2,R=190,COOL=.016,HEAT=.09;
  const BASE=[0,0,0],LIT=[148,198,250],HOT=[220,238,255];
  const lerp=(a,b,t)=>a+(b-a)*t;
  const lc=(a,b,t)=>a.map((v,i)=>Math.round(lerp(v,b[i],t)));
  const rc=(a,op)=>'rgba('+a[0]+','+a[1]+','+a[2]+','+(op??1)+')';
  function build(){
    W=cv.offsetWidth;H=cv.offsetHeight;
    cv.width=W*DPR;cv.height=H*DPR;ctx.scale(DPR,DPR);
    smx=W*.5;smy=H*.5;
    cols=Math.ceil(W/(CW+GAP))+1;rows=Math.ceil(H/(CH+GAP))+1;
    cells=[];
    for(let r=0;r<rows;r++)for(let c=0;c<cols;c++)
      cells.push({x:c*(CW+GAP),y:r*(CH+GAP),heat:Math.random()*.05});
  }
  function draw(){
    if(mx>-9999){smx+=(mx-smx)*.08;smy+=(my-smy)*.08;}
    ctx.clearRect(0,0,W,H);
    ctx.fillStyle='#000';ctx.fillRect(0,0,W,H);
    cells.forEach(cell=>{
      const cx=cell.x+CW/2,cy=cell.y+CH/2;
      const d=Math.sqrt((cx-smx)**2+(cy-smy)**2);
      const tgt=mx>-9999?Math.max(0,1-d/R):0;
      const rate=Math.pow(tgt,1.7)>cell.heat?HEAT:COOL;
      cell.heat+=(Math.pow(tgt,1.7)-cell.heat)*rate;
      const h=cell.heat;
      const col=h<.5?lc(BASE,LIT,h*2):lc(LIT,HOT,(h-.5)*2);
      ctx.fillStyle='#000';ctx.fillRect(cell.x-1,cell.y-1,CW+2,CH+2);
      ctx.fillStyle=rc(col,.84+h*.16);ctx.fillRect(cell.x,cell.y,CW,CH);
      const bA=.07+h*.24;ctx.strokeStyle='rgba(180,220,255,'+bA+')';ctx.lineWidth=.8;
      for(let i=1;i<=3;i++){const by=cell.y+(CH/4)*i;ctx.beginPath();ctx.moveTo(cell.x+2,by);ctx.lineTo(cell.x+CW-2,by);ctx.stroke();}
      const fA=.04+h*.15;ctx.strokeStyle='rgba(180,220,255,'+fA+')';ctx.lineWidth=.5;
      for(let i=1;i<=6;i++){const fx=cell.x+(CW/7)*i;ctx.beginPath();ctx.moveTo(fx,cell.y+1);ctx.lineTo(fx,cell.y+CH-1);ctx.stroke();}
      if(h>.55){const gA=(h-.55)*.75;const g=ctx.createRadialGradient(cx,cy,0,cx,cy,CW*.75);g.addColorStop(0,'rgba(200,230,255,'+gA+')');g.addColorStop(1,'rgba(0,0,0,0)');ctx.fillStyle=g;ctx.fillRect(cell.x,cell.y,CW,CH);}
    });
    requestAnimationFrame(draw);
  }
  cv.addEventListener('mousemove',e=>{mx=e.clientX;my=e.clientY},{passive:true});
  cv.addEventListener('mouseleave',()=>{mx=-9999;});
  window.addEventListener('resize',()=>{ctx.setTransform(1,0,0,1,0,0);build();},{passive:true});
  build();draw();
})();

// WIND TURBINE — Three.js GLB (Enercon E70)
// VOLTEX-style scroll-driven camera orbit + phase crossfade
(function(){
  const canvasWrap = document.getElementById('gen-canvas-wrap');
  const oldCanvas = document.getElementById('turbine-canvas');
  if(!canvasWrap || typeof THREE === 'undefined') return;

  // Hide 2D canvas + glb-slot
  if(oldCanvas) oldCanvas.style.display='none';
  const slot = document.getElementById('glb-slot');
  if(slot) slot.style.display='none';

  // Three.js setup
  const renderer = new THREE.WebGLRenderer({antialias:true, alpha:true});
  renderer.setPixelRatio(Math.min(window.devicePixelRatio,2));
  renderer.toneMapping = THREE.ACESFilmicToneMapping;
  renderer.toneMappingExposure = 1.2;
  renderer.outputColorSpace = THREE.SRGBColorSpace||THREE.sRGBEncoding;
  renderer.setClearColor(0x000000, 1);

  const W = canvasWrap.offsetWidth, H = canvasWrap.offsetHeight;
  renderer.setSize(W, H);
  renderer.domElement.style.cssText = 'position:absolute;inset:0;width:100%;height:100%;z-index:1;';
  canvasWrap.appendChild(renderer.domElement);

  const scene = new THREE.Scene();
  scene.background = new THREE.Color(0x000000);
  scene.fog = new THREE.FogExp2(0x000010, 0.007);

  // Camera — turbine well within frame at all times
  const camera = new THREE.PerspectiveCamera(36, W/H, 0.1, 500);
  camera.position.set(2, 8, 28);
  camera.lookAt(0, 6, 0);

  // Lighting rig — rich, dramatic
  scene.add(new THREE.AmbientLight(0x080e20, 0.7));

  const sun = new THREE.DirectionalLight(0xfff0cc, 1.6);
  sun.position.set(5, 20, 10);
  scene.add(sun);


  const fillLight = new THREE.DirectionalLight(0x0a1830, 0.3);
  fillLight.position.set(-4, -8, 6);
  scene.add(fillLight);

  const rimLight = new THREE.DirectionalLight(0x3060ee, 0.9);
  rimLight.position.set(-10, 10, -10);
  scene.add(rimLight);

  // Scroll-driven point lights
  const skyGlow = new THREE.PointLight(0x94c6fa, 0, 25);
  skyGlow.position.set(0, 16, 3);
  scene.add(skyGlow);

  const baseGlow = new THREE.PointLight(0x1a42cc, 0, 20);
  baseGlow.position.set(0, 0, 5);
  scene.add(baseGlow);

  // Star field
  const starGeo = new THREE.BufferGeometry();
  const starVerts = [];
  for(let i=0;i<1400;i++){
    starVerts.push((Math.random()-.5)*400,(Math.random()-.5)*400,(Math.random()-.5)*400);
  }
  starGeo.setAttribute('position', new THREE.Float32BufferAttribute(starVerts,3));
  const starMat = new THREE.PointsMaterial({color:0x94c6fa,size:.85,sizeAttenuation:true,transparent:true,opacity:.38});
  scene.add(new THREE.Points(starGeo,starMat));

  // Faint ground grid
  const grid = new THREE.GridHelper(80, 40, 0x123199, 0x0a1540);
  grid.position.y = -6;
  grid.material.opacity = 0.12;
  grid.material.transparent = true;
  scene.add(grid);

  // Load GLB from embedded base64
  let turbine = null;
  const loader = new THREE.GLTFLoader();
  loader.load(
    'data:model/gltf-binary;base64,',
    (gltf) => {
      turbine = gltf.scene;
      const box = new THREE.Box3().setFromObject(turbine);
      const size = box.getSize(new THREE.Vector3());
      const centre = box.getCenter(new THREE.Vector3());
      // Scale — well within frame
      const s = 20 / Math.max(size.x, size.y, size.z);
      turbine.scale.setScalar(s);
      turbine.position.sub(centre.multiplyScalar(s));
      turbine.position.y -= 0;

      // Enhance materials — metallic wind turbine
      turbine.traverse(child => {
        if(child.isMesh && child.material){
          const m = Array.isArray(child.material)?child.material:[child.material];
          m.forEach(mat => {
            if(mat.isMeshStandardMaterial||mat.isMeshPhysicalMaterial){
              mat.metalness = Math.max(mat.metalness||0, 0.58);
              mat.roughness = Math.min(mat.roughness||1, 0.38);
              mat.envMapIntensity = 1.4;
            }
          });
        }
      });
      scene.add(turbine);
    },
    undefined,
    (err) => { console.warn('GLB load error:', err); }
  );

  // Resize
  new ResizeObserver(() => {
    const W2 = canvasWrap.offsetWidth, H2 = canvasWrap.offsetHeight;
    renderer.setSize(W2,H2);
    camera.aspect = W2/H2;
    camera.updateProjectionMatrix();
  }).observe(canvasWrap);

  // ── Scroll state ──
  let scrollProg = 0, targetProg = 0;
  let camAngle = 0, targetAngle = 0;
  let camHeight = 8, targetCamH = 8;
  const clock = new THREE.Clock();

  // Scroll driver — Lenis + native fallback
  function onScroll(){
    const sec = document.getElementById('gen-section');
    if(!sec) return;
    const rect = sec.getBoundingClientRect();
    const hh = (document.querySelector('.site-header')||{offsetHeight:72}).offsetHeight; // dynamic header height
    const usable = sec.offsetHeight - (window.innerHeight - hh);
    targetProg = Math.max(0, Math.min(1, (hh - rect.top) / usable));
  }
  window.__lenisScrollCbs = window.__lenisScrollCbs || [];
  window.__lenisScrollCbs.push(onScroll);
  window.addEventListener('scroll', onScroll, {passive:true});
  onScroll();

  // Phase crossfade logic
  let prevPhase = -1;
  const PHASE_COUNT = 2;
  function updatePhases(phase, phaseT){
    if(phase !== prevPhase){
      const dir = phase > prevPhase ? 'up' : 'down';
      for(let i=0; i<PHASE_COUNT; i++){
        const el = document.getElementById('gen-phase-'+i);
        if(!el) continue;
        if(i === phase){
          el.classList.remove('exit-up','exit-down');
          el.classList.add('visible');
        } else if(el.classList.contains('visible')){
          el.classList.remove('visible');
          el.classList.add(dir==='up'?'exit-up':'exit-down');
          setTimeout(()=>el.classList.remove('exit-up','exit-down'),500);
        }
      }
      prevPhase = phase;
    }
    // Update horizontal progress dots
    for(let i=0; i<PHASE_COUNT; i++){
      const dot = document.getElementById('ghd'+i);
      if(dot) dot.classList.toggle('active', i<=phase);
    }
    // Update horizontal progress fill
    for(let i=0; i<PHASE_COUNT-1; i++){
      const fill = document.getElementById('ghf'+i);
      if(fill) fill.style.width = i<phase ? '100%' : i===phase ? (phaseT*100)+'%' : '0%';
    }
    // Update vertical progress
    const gpf = document.getElementById('gpf');
    if(gpf) gpf.style.height = (scrollProg*100)+'%';
    const gpd0 = document.getElementById('gpd0');
    const gpd1 = document.getElementById('gpd1');
    if(gpd0) gpd0.classList.toggle('active', true);
    if(gpd1) gpd1.classList.toggle('active', phase >= 1);
    // Caption update
    const cap = document.getElementById('gen-caption');
    if(cap) cap.textContent = phase === 0 ? 'Yaloak South Wind Farm \u2014 VIC' : 'Glenrowan Solar Farm \u2014 VIC';
  }

  // Only render when section is in view
  let isVisible = false;
  new IntersectionObserver(entries=>{isVisible=entries[0].isIntersecting;},{threshold:0})
    .observe(document.getElementById('gen-section'));

  // Animation loop — scroll-driven camera orbit
  function animate(){
    requestAnimationFrame(animate);
    if(!isVisible) return;
    const t = clock.getElapsedTime();

    // Lerp scroll progress
    scrollProg += (targetProg - scrollProg) * 0.055;
    // Dynamic fog breathes with time
    if(scene.fog) scene.fog.density = 0.004 + scrollProg*0.008 + Math.sin(t*0.18)*0.001;

    // Drive CSS gradient bloom
    canvasWrap.style.setProperty('--gen-scroll', scrollProg.toFixed(3));

    // Phase calculation
    const phase = Math.min(PHASE_COUNT-1, Math.floor(scrollProg * PHASE_COUNT));
    const phaseT = (scrollProg * PHASE_COUNT) % 1;
    updatePhases(phase, phaseT);

    // Camera orbit — scroll drives angle + height
    targetAngle = scrollProg * Math.PI * 1.5;  // 270° total rotation
    targetCamH = 8 - scrollProg * 1.5;          // 8 → 6.5 descend
    camAngle += (targetAngle - camAngle) * 0.045;
    camHeight += (targetCamH - camHeight) * 0.045;

    const camR = 28 - scrollProg * 4;           // 28 → 24 tighten
    camera.position.x = Math.sin(camAngle) * camR;
    camera.position.z = Math.cos(camAngle) * camR;
    camera.position.y = camHeight;
    camera.lookAt(0, 6 + scrollProg * 2, 0);    // look tracks upward

    // Scroll-driven lights
    skyGlow.intensity = Math.min(2.5, scrollProg * 5);
    baseGlow.intensity = Math.min(2, Math.max(0, (scrollProg - 0.1) * 4));

    // Turbine — gentle sway + blade spin
    if(turbine){
      turbine.rotation.z = Math.sin(t * 0.6) * Math.max(0, (scrollProg - 0.3) * 0.012);
      turbine.traverse(child => {
        if(child.name && /rotor|blade|spin|fan|prop|nabe/i.test(child.name)){
          child.rotation.z += 0.018 + scrollProg * 0.012;
        }
      });
    }

    // Star shimmer
    starMat.opacity = 0.2 + Math.sin(t * 0.3) * 0.08 + scrollProg * 0.15;

    renderer.render(scene, camera);
  }
  animate();
})();
// ── BENTO CANVAS — dark solar panel grid background ──
// Subtle grid cells with faint blue glow on mouse proximity
(function(){
  const cv = document.getElementById('bento-canvas');
  if(!cv) return;
  const ctx = cv.getContext('2d');
  const DPR = Math.min(window.devicePixelRatio||1, 2);
  let W, H, cols, rows, cells=[];
  let mx=-9999, my=-9999, smx=0, smy=0;
  const CW=48, CH=34, GAP=2, R=180;
  const BG=[0,0,0], DIM=[12,18,26], LIT=[35,60,100];
  const lerp=(a,b,t)=>a+(b-a)*t;
  const lc=(a,b,t)=>a.map((v,i)=>Math.round(lerp(v,b[i],t)));
  const rc=(a,op)=>`rgba(${a[0]},${a[1]},${a[2]},${op??1})`;

  function build(){
    W=cv.offsetWidth; H=cv.offsetHeight;
    if(!W||!H) return;
    cv.width=W*DPR; cv.height=H*DPR; ctx.scale(DPR,DPR);
    smx=W*.5; smy=H*.5;
    cols=Math.ceil(W/(CW+GAP))+1; rows=Math.ceil(H/(CH+GAP))+1;
    cells=[];
    for(let r=0;r<rows;r++) for(let c=0;c<cols;c++)
      cells.push({x:c*(CW+GAP),y:r*(CH+GAP),heat:0});
  }

  function draw(){
    if(mx>-9999){smx+=(mx-smx)*.06;smy+=(my-smy)*.06;}
    ctx.clearRect(0,0,W,H);
    ctx.fillStyle=rc(BG);ctx.fillRect(0,0,W,H);

    cells.forEach(cell=>{
      const cx=cell.x+CW/2, cy=cell.y+CH/2;
      const d=mx>-9999?Math.sqrt((cx-smx)**2+(cy-smy)**2):9999;
      const tgt=Math.max(0,1-d/R);
      cell.heat+=(Math.pow(tgt,2)-cell.heat)*.04;
      const h=cell.heat;
      const col=lc(DIM,LIT,h);

      // Cell background
      ctx.fillStyle=rc(col,.6+h*.4);
      ctx.fillRect(cell.x,cell.y,CW,CH);

      // Subtle horizontal lines (panel bus bars)
      const lA=.08+h*.12;
      ctx.strokeStyle=`rgba(80,120,180,${lA})`;ctx.lineWidth=.5;
      for(let i=1;i<=3;i++){
        const by=cell.y+(CH/4)*i;
        ctx.beginPath();ctx.moveTo(cell.x+2,by);ctx.lineTo(cell.x+CW-2,by);ctx.stroke();
      }

      // Glow on proximity
      if(h>.08){
        const gA=h*.2;
        const g=ctx.createRadialGradient(cx,cy,0,cx,cy,CW*.7);
        g.addColorStop(0,`rgba(148,198,250,${gA})`);
        g.addColorStop(1,'rgba(0,0,0,0)');
        ctx.fillStyle=g;ctx.fillRect(cell.x,cell.y,CW,CH);
      }
    });

    requestAnimationFrame(draw);
  }

  const parent=cv.parentElement;
  parent.addEventListener('mousemove',e=>{
    const r=cv.getBoundingClientRect();
    mx=e.clientX-r.left; my=e.clientY-r.top;
  },{passive:true});
  parent.addEventListener('mouseleave',()=>{mx=-9999;},{passive:true});

  new ResizeObserver(()=>{
    ctx.setTransform(1,0,0,1,0,0);build();
  }).observe(cv);
  build();draw();
})();



// ── FOOTER REVEAL ──
(function(){
  const footer = document.getElementById('site-footer');
  if(!footer) return;
  const obs = new IntersectionObserver(entries=>{
    if(entries[0].isIntersecting){ footer.classList.add('footer-in'); obs.disconnect(); }
  },{threshold:0.04});
  obs.observe(footer);
})();

// ── BENTO STAT COUNTERS — bidirectional, tied to tile anim-in ──
// Fires each time tile enters view, resets when tile leaves
(function(){
  const ease = t => t<.5 ? 2*t*t : -1+(4-2*t)*t;

  function runCounter(el){
    const target = parseInt(el.dataset.count, 10);
    const suffix = el.dataset.suffix||'';
    const dur = 1800;
    let raf;
    const start = performance.now();
    function tick(now){
      const p = Math.min((now-start)/dur, 1);
      el.textContent = Math.round(ease(p)*target).toLocaleString()+suffix;
      if(p<1){ raf = requestAnimationFrame(tick); }
      else { el.textContent = target.toLocaleString()+suffix; el.classList.add('counted'); }
    }
    el._cancelCounter = ()=>{ cancelAnimationFrame(raf); };
    raf = requestAnimationFrame(tick);
  }

  document.querySelectorAll('.bento-tile.anim-el').forEach(tile=>{
    const stat = tile.querySelector('.bento-stat[data-count]');
    if(!stat) return;

    new MutationObserver(()=>{
      if(tile.classList.contains('anim-in')){
        // Entered — start counter, delayed to sync with tile's base delay
        const bd = parseFloat(getComputedStyle(tile).getPropertyValue('--bd'))||0;
        setTimeout(()=>runCounter(stat), bd*1000 + 80);
      } else {
        // Left — cancel any running counter + reset display
        if(stat._cancelCounter) stat._cancelCounter();
        stat.textContent = '0'+(stat.dataset.suffix||'');
        stat.classList.remove('counted');
      }
    }).observe(tile, {attributes:true, attributeFilter:['class']});
  });
})();

// ── HERO PARALLAX ──
(function(){
  const content = document.querySelector('.hero-content');
  if(!content) return;
  let ticking = false;
  window.addEventListener('scroll',()=>{
    if(!ticking){ requestAnimationFrame(()=>{ content.style.transform='translateY('+Math.round(window.scrollY*.32)+'px)'; ticking=false; }); ticking=true; }
  },{passive:true});
})();

// ── BENTO TILE 3D TILT ──
(function(){
  if(window.matchMedia('(hover:none)').matches) return;
  document.querySelectorAll('.bento-tile').forEach(tile=>{
    tile.addEventListener('mousemove',e=>{
      const r=tile.getBoundingClientRect();
      const x=(e.clientX-r.left)/r.width-.5, y=(e.clientY-r.top)/r.height-.5;
      tile.style.transform='perspective(700px) rotateY('+(x*10)+'deg) rotateX('+(-y*7)+'deg) scale(1.025)';
    });
    tile.addEventListener('mouseleave',()=>{ tile.style.transform=''; });
  });
})();



// ── FOOTER CANVAS — rising ambient particles ──
(function(){
  const cv = document.getElementById('footer-canvas');
  if(!cv) return;
  const ctx = cv.getContext('2d');
  const DPR = Math.min(window.devicePixelRatio||1, 2);
  let W=0, H=0, pts=[];

  function build(){
    W=cv.parentElement.offsetWidth; H=cv.parentElement.offsetHeight;
    if(!W||!H) return;
    cv.width=W*DPR; cv.height=H*DPR; ctx.scale(DPR,DPR);
    pts = Array.from({length:75},()=>({
      x:Math.random()*W, y:Math.random()*H,
      r:Math.random()*1.5+.2,
      vy:-(Math.random()*.38+.08),
      vx:(Math.random()-.5)*.18,
      op:Math.random()*.22+.04,
      ph:Math.random()*Math.PI*2
    }));
  }

  let visible=false, t=0;
  new IntersectionObserver(e=>{visible=e[0].isIntersecting;},{threshold:0}).observe(cv.parentElement);

  function draw(){
    requestAnimationFrame(draw);
    if(!visible) return;
    t+=.013;
    ctx.clearRect(0,0,W,H);
    pts.forEach(p=>{
      p.ph+=.018;
      const a=p.op*(.55+.45*Math.sin(p.ph));
      ctx.beginPath(); ctx.arc(p.x,p.y,p.r,0,Math.PI*2);
      ctx.fillStyle='rgba(148,198,250,'+a.toFixed(3)+')'; ctx.fill();
      p.y+=p.vy; p.x+=p.vx+Math.sin(t+p.ph)*.09;
      if(p.y<-p.r*2){p.y=H+p.r; p.x=Math.random()*W;}
      if(p.x<0)p.x=W; if(p.x>W)p.x=0;
    });
  }
  new ResizeObserver(()=>{ctx.setTransform(1,0,0,1,0,0);build();}).observe(cv.parentElement);
  build(); draw();
})();

// ── PAGE LOADER ──
(function(){
  var loader = document.getElementById('page-loader');
  if(!loader) return;

  // Lock scroll while loader covers the page
  document.body.style.overflow = 'hidden';

  // Start progress bar on next frame so CSS transition fires
  requestAnimationFrame(function(){
    var fill = document.getElementById('loader-bar-fill');
    if(fill) fill.style.width = '100%';
  });

  // Dismiss after 3.5s, restore scroll immediately
  setTimeout(function(){
    loader.classList.add('loaded');
    document.body.style.overflow = '';
  }, 3500);
})();

// ── MOBILE GEN-SECTION TEXT ANIMATION ──
// Mobile gen-section uses the same scroll-driven updatePhases() as desktop — no extra observer needed.

// ── HERO ENTRANCE + SCROLL RE-ANIMATION ──
(function(){
  var heroEls  = document.querySelectorAll('.hero-el');
  var header   = document.querySelector('.site-header');
  var heroSec  = document.getElementById('hero');
  var ready    = false;

  function heroIn(){
    heroEls.forEach(function(el){ el.classList.add('hero-in'); });
  }
  function heroOut(){
    heroEls.forEach(function(el){ el.classList.remove('hero-in'); });
  }

  // Fire hero content slightly before loader finishes fading — elements
  // emerge through the dissolving overlay for a seamless "entering" feel
  setTimeout(function(){
    ready = true;
    if(header) header.classList.add('nav-in');
    heroIn();
  }, 3250);

  // Bidirectional scroll — reset & replay when scrolling back to hero
  if(heroSec){
    new IntersectionObserver(function(entries){
      entries.forEach(function(e){
        if(!ready) return;
        if(e.intersectionRatio >= 0.15) heroIn();
        else if(e.intersectionRatio === 0) heroOut();
      });
    }, { threshold: [0, 0.15] }).observe(heroSec);
  }
})();
